#include <iostream>
#include "antlr4-runtime.h"
#include "SYsULexer.h"
#include "SYsUParser.h"

using namespace antlr4;

int main(int argc, const char* argv[]) {
  if (argc < 2) {
    std::cerr << "Usage: " << argv[0] << " <input-file>" << std::endl;
    return 1;
  }

  std::ifstream stream;
  stream.open(argv[1]);

  ANTLRInputStream input(stream);
  SYsULexer lexer(&input);
  CommonTokenStream tokens(&lexer);

  tokens.fill();
  for (auto token : tokens.getTokens()) {
    // Cast to our custom token type
    auto positionedToken = dynamic_cast<SYsULexer::PositionedToken*>(token);
    if (positionedToken) {
      std::cout << token->toString() << " ";

      // Format token as required
      std::string tokenName = token->getType() == EOF ? "eof" : lexer.getVocabulary().getSymbolicName(token->getType());
      if (tokenName.empty()) {
        tokenName = std::to_string(token->getType());
      }

      std::cout << tokenName << " '" << token->getText() << "'";
      if (positionedToken->startOfLine) std::cout << " [StartOfLine]";
      if (positionedToken->leadingSpace) std::cout << " [LeadingSpace]";
      std::cout << " Loc=<" << positionedToken->filename 
                << ":" << token->getLine() 
                << ":" << positionedToken->col << ">" << std::endl;
    } else {
      // Fallback to default formatting
      std::cout << token->toString() << std::endl;
    }
  }

  return 0;
}

